/* ─── Birthday Song Player using Web Audio API ─── */
function useBirthdaySong() {
  const ctxRef = useRef(null);
  const [playing, setPlaying] = useState(false);
  const [started, setStarted] = useState(false);
  const nodesRef = useRef([]);

  const stopAll = useCallback(() => {
    nodesRef.current.forEach(n => { try { n.stop(); } catch(e){} });
    nodesRef.current = [];
    setPlaying(false);
  }, []);

  const playNote = useCallback((ctx, freq, startTime, duration, gain = 0.35) => {
    const osc = ctx.createOscillator();
    const gainNode = ctx.createGain();
    const osc2 = ctx.createOscillator();
    const gainNode2 = ctx.createGain();

    osc.type = "sine";
    osc.frequency.setValueAtTime(freq, startTime);
    gainNode.gain.setValueAtTime(0, startTime);
    gainNode.gain.linearRampToValueAtTime(gain, startTime + 0.02);
    gainNode.gain.linearRampToValueAtTime(gain * 0.7, startTime + duration * 0.5);
    gainNode.gain.linearRampToValueAtTime(0, startTime + duration);

    osc2.type = "triangle";
    osc2.frequency.setValueAtTime(freq * 2, startTime);
    gainNode2.gain.setValueAtTime(0, startTime);
    gainNode2.gain.linearRampToValueAtTime(gain * 0.15, startTime + 0.02);
    gainNode2.gain.linearRampToValueAtTime(0, startTime + duration);

    osc.connect(gainNode); gainNode.connect(ctx.destination);
    osc2.connect(gainNode2); gainNode2.connect(ctx.destination);
    osc.start(startTime); osc.stop(startTime + duration + 0.05);
    osc2.start(startTime); osc2.stop(startTime + duration + 0.05);
    nodesRef.current.push(osc, osc2);
  }, []);

  const play = useCallback(() => {
    if (playing) { stopAll(); return; }
    if (!ctxRef.current) ctxRef.current = new (window.AudioContext || window.webkitAudioContext)();
    const ctx = ctxRef.current;
    if (ctx.state === "suspended") ctx.resume();

    // Happy Birthday notes: C C D C F E | C C D C G F | C C C5 A F E D | Bb Bb A F G F
    const C4=261.63, D4=293.66, E4=329.63, F4=349.23, G4=392.00,
          A4=440.00, Bb4=466.16, C5=523.25;
    const Q=0.42, H=0.84, DQ=0.63, E=0.21;

    // [freq, duration]
    const melody = [
      [C4,DQ],[C4,E],[D4,H],[C4,H],[F4,H],[E4,H*1.5],
      [C4,DQ],[C4,E],[D4,H],[C4,H],[G4,H],[F4,H*1.5],
      [C4,DQ],[C4,E],[C5,H],[A4,H],[F4,H],[E4,H],[D4,H*1.5],
      [Bb4,DQ],[Bb4,E],[A4,H],[F4,H],[G4,H],[F4,H*2],
    ];

    let t = ctx.currentTime + 0.1;
    melody.forEach(([freq, dur]) => {
      playNote(ctx, freq, t, dur * 0.9);
      t += dur;
    });

    setPlaying(true);
    setStarted(true);
    const totalDur = melody.reduce((s,[,d]) => s+d, 0) * 1000 + 500;
    setTimeout(() => setPlaying(false), totalDur);
  }, [playing, stopAll, playNote]);

  return { playing, started, play, stopAll };
}

/* ─── Music Player UI ─── */
function MusicPlayer() {
  const { playing, started, play } = useBirthdaySong();
  const [bars, setBars] = useState([3,5,8,6,4,7,5,3]);

  useEffect(() => {
    if (!playing) return;
    const interval = setInterval(() => {
      setBars(prev => prev.map(() => Math.floor(Math.random() * 10) + 2));
    }, 150);
    return () => clearInterval(interval);
  }, [playing]);

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", margin: "32px 0 48px", animation: "fadeUp 1s ease 1.35s both" }}>
      {/* Waveform visualizer */}
      <div style={{ display: "flex", alignItems: "center", gap: 4, height: 40, marginBottom: 20, opacity: playing ? 1 : 0.3, transition: "opacity 0.5s" }}>
        {bars.map((h, i) => (
          <div key={i} style={{
            width: 4, borderRadius: 2,
            background: "linear-gradient(180deg, #c9a84c, #8a6820)",
            height: playing ? h * 3 : 6,
            transition: playing ? "height 0.15s ease" : "height 0.5s ease",
            transformOrigin: "bottom"
          }} />
        ))}
      </div>

      {/* Play button */}
      <button onClick={play} style={{
        width: 72, height: 72, borderRadius: "50%",
        background: playing
          ? "linear-gradient(135deg, #2a1c0a, #1a1208)"
          : "linear-gradient(135deg, #c9a84c, #a07830)",
        border: playing ? "2px solid #c9a84c" : "none",
        cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center",
        boxShadow: playing ? "0 0 20px rgba(201,168,76,0.4)" : "0 0 30px rgba(201,168,76,0.25)",
        transition: "all 0.3s ease",
        outline: "none",
        animation: playing ? "pulse 1.5s ease-in-out infinite" : "none"
      }}>
        {playing ? (
          <div style={{ display: "flex", gap: 5 }}>
            <div style={{ width: 4, height: 22, background: "#c9a84c", borderRadius: 2 }} />
            <div style={{ width: 4, height: 22, background: "#c9a84c", borderRadius: 2 }} />
          </div>
        ) : (
          <div style={{ width: 0, height: 0, borderTop: "12px solid transparent", borderBottom: "12px solid transparent", borderLeft: "20px solid #0a0705", marginLeft: 4 }} />
        )}
      </button>

      <p style={{ marginTop: 14, fontSize: 11, letterSpacing: 3, color: "#c9a84c", textTransform: "uppercase" }}>
        {playing ? "♪ Playing for Ariya ♪" : started ? "Play Again" : "Play Birthday Song"}
      </p>
      <p style={{ marginTop: 4, fontSize: 10, color: "#5a4a2a", letterSpacing: 1 }}>
        Happy Birthday To You — Web Audio
      </p>
    </div>
  );
}

/* ─── Sound Effects ─── */
function useSoundEffects() {
  const ctxRef = useRef(null);
  const getCtx = () => {
    if (!ctxRef.current) ctxRef.current = new (window.AudioContext || window.webkitAudioContext)();
    if (ctxRef.current.state === "suspended") ctxRef.current.resume();
    return ctxRef.current;
  };
  const playTick = () => { try { const ctx=getCtx(),osc=ctx.createOscillator(),g=ctx.createGain(); osc.type="sine"; osc.frequency.value=880; g.gain.setValueAtTime(0.07,ctx.currentTime); g.gain.linearRampToValueAtTime(0,ctx.currentTime+0.09); osc.connect(g); g.connect(ctx.destination); osc.start(); osc.stop(ctx.currentTime+0.1); } catch(e){} };
  const playPop = () => { try { const ctx=getCtx(),osc=ctx.createOscillator(),g=ctx.createGain(); osc.type="sine"; osc.frequency.setValueAtTime(600,ctx.currentTime); osc.frequency.exponentialRampToValueAtTime(200,ctx.currentTime+0.18); g.gain.setValueAtTime(0.16,ctx.currentTime); g.gain.linearRampToValueAtTime(0,ctx.currentTime+0.18); osc.connect(g); g.connect(ctx.destination); osc.start(); osc.stop(ctx.currentTime+0.2); } catch(e){} };
  const playChime = () => { try { const ctx=getCtx(); [523.25,659.25,783.99].forEach((f,i)=>{ const osc=ctx.createOscillator(),g=ctx.createGain(); osc.type="sine"; osc.frequency.value=f; g.gain.setValueAtTime(0,ctx.currentTime+i*0.13); g.gain.linearRampToValueAtTime(0.13,ctx.currentTime+i*0.13+0.02); g.gain.linearRampToValueAtTime(0,ctx.currentTime+i*0.13+0.55); osc.connect(g); g.connect(ctx.destination); osc.start(ctx.currentTime+i*0.13); osc.stop(ctx.currentTime+i*0.13+0.65); }); } catch(e){} };
  const playWhoosh = () => { try { const ctx=getCtx(),buf=ctx.createBuffer(1,ctx.sampleRate*0.25,ctx.sampleRate),d=buf.getChannelData(0); for(let i=0;i<d.length;i++) d[i]=(Math.random()*2-1)*(1-i/d.length)*0.8; const src=ctx.createBufferSource(); src.buffer=buf; const filt=ctx.createBiquadFilter(); filt.type="bandpass"; filt.frequency.value=1200; const g=ctx.createGain(); g.gain.setValueAtTime(0.12,ctx.currentTime); g.gain.linearRampToValueAtTime(0,ctx.currentTime+0.25); src.connect(filt); filt.connect(g); g.connect(ctx.destination); src.start(); } catch(e){} };
  return { playTick, playPop, playChime, playWhoosh };
}

/* ─── Scroll Reveal Hook ─── */
function useScrollReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVisible(true); }, { threshold: 0.12 });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);
  return [ref, visible];
}

/* ─── Scroll Reveal Section ─── */
function Section({ children }) {
  const [ref, visible] = useScrollReveal();
  return (
    <div ref={ref} style={{ opacity: visible?1:0, transform: visible?"translateY(0)":"translateY(32px)", transition: "opacity 0.85s ease, transform 0.85s ease" }}>
      {children}
    </div>
  );
}

/* ─── Confetti ─── */
function Confetti({ active, onDone }) {
  const canvasRef = useRef(null);
  useEffect(() => {
    if (!active) return;
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext("2d");
    canvas.width = window.innerWidth; canvas.height = window.innerHeight;
    const colors = ["#c9a84c","#f5edd8","#e8c85a","#fff8e7","#d4a843","#ffe082","#ffd700","#fff"];
    const pieces = Array.from({length:150}, () => ({
      x: Math.random()*canvas.width, y: Math.random()*canvas.height - canvas.height*1.1,
      w: Math.random()*11+5, h: Math.random()*6+3,
      r: Math.random()*Math.PI*2, vx:(Math.random()-0.5)*5,
      vy: Math.random()*4+2, vr:(Math.random()-0.5)*0.2,
      color: colors[Math.floor(Math.random()*colors.length)], alpha:1
    }));
    let raf;
    const draw = () => {
      ctx.clearRect(0,0,canvas.width,canvas.height);
      pieces.forEach(p => {
        p.x+=p.vx; p.y+=p.vy; p.r+=p.vr;
        if (p.y > canvas.height*0.72) p.alpha = Math.max(0, p.alpha-0.013);
        ctx.save(); ctx.translate(p.x,p.y); ctx.rotate(p.r);
        ctx.globalAlpha = Math.max(0,p.alpha); ctx.fillStyle = p.color;
        ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h); ctx.restore();
      });
      if (pieces.some(p=>p.alpha>0)) raf = requestAnimationFrame(draw);
      else onDone && onDone();
    };
    draw();
    return () => cancelAnimationFrame(raf);
  }, [active, onDone]);
  if (!active) return null;
  return <canvas ref={canvasRef} style={{position:"fixed",top:0,left:0,width:"100%",height:"100%",pointerEvents:"none",zIndex:100}} />;
}

