/* ─── Particles ─── */
function Particles() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    let W, H, particles = [], raf;
    const resize = () => { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; };
    resize();
    window.addEventListener("resize", resize);
    class Particle {
      constructor(init) { this.x = Math.random()*(W||800); this.y = init ? Math.random()*(H||600) : (H||600)+10; this.r = Math.random()*1.5+0.3; this.speed = Math.random()*0.4+0.1; this.opacity = Math.random()*0.5+0.1; this.drift = (Math.random()-0.5)*0.3; this.gold = Math.random()>0.5; }
      reset() { this.x=Math.random()*W; this.y=H+10; this.r=Math.random()*1.5+0.3; this.speed=Math.random()*0.4+0.1; this.opacity=Math.random()*0.5+0.1; this.drift=(Math.random()-0.5)*0.3; this.gold=Math.random()>0.5; }
      update() { this.y-=this.speed; this.x+=this.drift; if(this.y<-10) this.reset(); }
      draw() { ctx.beginPath(); ctx.arc(this.x,this.y,this.r,0,Math.PI*2); ctx.fillStyle=this.gold?`rgba(201,168,76,${this.opacity})`:`rgba(245,237,216,${this.opacity*0.4})`; ctx.fill(); }
    }
    for(let i=0;i<80;i++) particles.push(new Particle(true));
    const anim = () => { ctx.clearRect(0,0,W,H); particles.forEach(p=>{p.update();p.draw();}); raf=requestAnimationFrame(anim); };
    anim();
    return () => { cancelAnimationFrame(raf); window.removeEventListener("resize", resize); };
  }, []);
  return <canvas ref={canvasRef} style={{ position:"fixed",top:0,left:0,width:"100%",height:"100%",pointerEvents:"none",zIndex:0 }} />;
}

/* ─── Candle ─── */
function Candle({ delay = 0, onBlow, sounds }) {
  const [blown, setBlown] = useState(false);
  const [smoke, setSmoke] = useState(false);
  const handleBlow = () => {
    if (blown) return;
    setBlown(true); setSmoke(true);
    sounds && sounds.playWhoosh();
    onBlow && onBlow();
    setTimeout(() => setSmoke(false), 2200);
  };
  return (
    <div onClick={handleBlow} title={blown ? "" : "Click to blow out! 💨"}
      style={{ display:"flex",flexDirection:"column",alignItems:"center",gap:2,cursor:blown?"default":"pointer",position:"relative",userSelect:"none" }}>
      {smoke && [0,1,2].map(i => (
        <div key={i} style={{ position:"absolute",top:-26,left:"50%",width:6,height:6,borderRadius:"50%",
          background:"rgba(210,210,210,0.75)",
          animation:`smokeRise 1.9s ${i*0.38}s ease-out forwards`,
          transformOrigin:"center bottom" }} />
      ))}
      {!blown
        ? <div style={{ width:8,height:14,background:"radial-gradient(ellipse at bottom,#f9c74f,#f3722c,transparent)",borderRadius:"50% 50% 30% 30%",animation:`flicker 1.5s ease-in-out ${delay}s infinite alternate` }} />
        : <div style={{ width:8,height:4,background:"#555",borderRadius:"50%",opacity:0.55,marginBottom:2 }} />
      }
      <div style={{ width:10,height:28,background:`linear-gradient(180deg,${blown?"#6a5820":"#c9a84c"},#8a6820)`,borderRadius:1,transition:"background 0.4s" }} />
      <div style={{ width:14,height:4,background:"#8a6820",borderRadius:1 }} />
    </div>
  );
}

/* ─── Photo Frame ─── */
function PhotoFrame({ sounds }) {
  const allPhotos = [img1, img2, img3, img4, img5];
  const [idx, setIdx] = useState(3);
  const [fading, setFading] = useState(false);
  const cycle = (next) => {
    if (fading) return;
    setFading(true);
    sounds && sounds.playTick();
    setTimeout(() => {
      setIdx(next !== undefined ? next : i => (i+1) % allPhotos.length);
      setFading(false);
    }, 280);
  };
  return (
    <div style={{ position:"relative",width:210,height:210,margin:"0 auto 24px" }}>
      <svg style={{ position:"absolute",inset:-10,width:"calc(100% + 20px)",height:"calc(100% + 20px)",animation:"rotateBorder 10s linear infinite" }} viewBox="0 0 230 230">
        <defs><linearGradient id="gr" x1="0" y1="0" x2="1" y2="1"><stop offset="0%" stopColor="#c9a84c" stopOpacity="0.2"/><stop offset="50%" stopColor="#c9a84c" stopOpacity="1"/><stop offset="100%" stopColor="#c9a84c" stopOpacity="0.2"/></linearGradient></defs>
        <circle cx="115" cy="115" r="110" fill="none" stroke="url(#gr)" strokeWidth="1.5" strokeDasharray="8 6"/>
      </svg>
      <div onClick={() => cycle()} title="Click to cycle photos ✦"
        style={{ width:210,height:210,borderRadius:"50%",overflow:"hidden",border:"3px solid #1a1410",cursor:"pointer",opacity:fading?0:1,transition:"opacity 0.28s ease" }}>
        <img src={allPhotos[idx]} alt="Ariya Hayat" style={{ width:"100%",height:"100%",objectFit:"cover",objectPosition:"top center" }} />
      </div>
      <div style={{ display:"flex",justifyContent:"center",gap:6,position:"absolute",bottom:-20,left:0,right:0 }}>
        {allPhotos.map((_,i) => (
          <div key={i} onClick={() => cycle(i)}
            style={{ width:5,height:5,borderRadius:"50%",background:i===idx?"#c9a84c":"#3a2e1a",cursor:"pointer",transition:"background 0.3s, transform 0.3s",transform:i===idx?"scale(1.4)":"scale(1)" }} />
        ))}
      </div>
    </div>
  );
}

/* ─── Quote Carousel ─── */
function QuoteCarousel({ sounds }) {
  const [current, setCurrent] = useState(0);
  const [copied, setCopied] = useState(false);
  const touchX = useRef(null);
  const timerRef = useRef(null);

  const resetTimer = () => {
    clearInterval(timerRef.current);
    timerRef.current = setInterval(() => setCurrent(c => (c+1) % quotes.length), 4500);
  };
  useEffect(() => { resetTimer(); return () => clearInterval(timerRef.current); }, []);

  const go = (i) => { setCurrent(i); sounds && sounds.playTick(); resetTimer(); };

  const copyQuote = () => {
    const q = quotes[current];
    navigator.clipboard && navigator.clipboard.writeText(`"${q.text}" — ${q.attr}`).then(() => {
      setCopied(true); sounds && sounds.playChime();
      setTimeout(() => setCopied(false), 2200);
    });
  };

  const onTouchStart = e => { touchX.current = e.touches[0].clientX; };
  const onTouchEnd = e => {
    if (touchX.current === null) return;
    const dx = e.changedTouches[0].clientX - touchX.current;
    if (Math.abs(dx) > 45) go(dx < 0 ? (current+1)%quotes.length : (current-1+quotes.length)%quotes.length);
    touchX.current = null;
  };

  return (
    <div style={{ marginBottom:56 }}>
      <div onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}
        style={{ position:"relative",minHeight:180,display:"flex",alignItems:"center",justifyContent:"center" }}>
        {quotes.map((q,i) => (
          <div key={i} style={{ position:"absolute",width:"100%",textAlign:"center",opacity:i===current?1:0,transform:i===current?"translateY(0)":"translateY(20px)",transition:"opacity 0.8s ease,transform 0.8s ease",pointerEvents:i===current?"auto":"none" }}>
            <span style={{ fontFamily:"'Cormorant Garamond',serif",fontSize:80,color:"#c9a84c",lineHeight:0.5,opacity:0.35,display:"block",marginBottom:8 }}>"</span>
            <p style={{ fontFamily:"'Cormorant Garamond',serif",fontSize:"clamp(18px,3vw,26px)",fontStyle:"italic",fontWeight:300,color:"#f5edd8",lineHeight:1.65,maxWidth:600,margin:"0 auto 14px" }}>{q.text}</p>
            <p style={{ fontSize:11,letterSpacing:3,color:"#c9a84c",textTransform:"uppercase" }}>— {q.attr}</p>
          </div>
        ))}
      </div>
      <div style={{ display:"flex",justifyContent:"center",gap:8,marginTop:26,marginBottom:16 }}>
        {quotes.map((_,i) => (
          <div key={i} onClick={() => go(i)} style={{ width:6,height:6,borderRadius:"50%",background:i===current?"#c9a84c":"#3a2e1a",cursor:"pointer",transition:"background 0.3s" }} />
        ))}
      </div>
      <div style={{ textAlign:"center" }}>
        <button onClick={copyQuote} style={{ background:"none",border:`1px solid ${copied?"#c9a84c":"#2a2010"}`,borderRadius:3,padding:"7px 18px",color:copied?"#c9a84c":"#5a4a2a",fontSize:10,letterSpacing:2.5,textTransform:"uppercase",cursor:"pointer",transition:"all 0.3s",outline:"none" }}>
          {copied ? "✓ Copied to Clipboard" : "✦ Copy This Quote"}
        </button>
        <p style={{ fontSize:9,color:"#2a2010",marginTop:6,letterSpacing:1 }}>← swipe to browse →</p>
      </div>
    </div>
  );
}

/* ─── Image Strip ─── */
function ImageStrip() {
  const doubled = [...photos,...photos];
  return (
    <div style={{ marginBottom:56 }}>
      <div style={{ textAlign:"center",marginBottom:22 }}>
        <h2 style={{ fontFamily:"'Cormorant Garamond',serif",fontWeight:300,fontSize:34,color:"#f5edd8" }}>Through the Years</h2>
        <div style={{ display:"flex",alignItems:"center",gap:12,justifyContent:"center",marginTop:10 }}>
          <div style={{ width:50,height:1,background:"linear-gradient(90deg,transparent,#c9a84c)" }} />
          <span style={{ fontSize:10,color:"#c9a84c" }}>✦</span>
          <div style={{ width:50,height:1,background:"linear-gradient(90deg,#c9a84c,transparent)" }} />
        </div>
      </div>
      <div style={{ overflow:"hidden",position:"relative" }}>
        <div style={{ position:"absolute",top:0,bottom:0,left:0,width:80,background:"linear-gradient(90deg,#0a0705,transparent)",zIndex:2,pointerEvents:"none" }} />
        <div style={{ position:"absolute",top:0,bottom:0,right:0,width:80,background:"linear-gradient(270deg,#0a0705,transparent)",zIndex:2,pointerEvents:"none" }} />
        <div style={{ display:"flex",gap:14,animation:"slideStrip 28s linear infinite",width:"max-content" }}>
          {doubled.map((p,i) => (
            <div key={i} style={{ width:180,height:240,flexShrink:0,borderRadius:3,overflow:"hidden",border:"1px solid #2a2010",position:"relative" }}>
              <img src={p.src} alt={`Ariya ${(i%5)+1}`} style={{ width:"100%",height:"100%",objectFit:"cover",objectPosition:"top center",display:"block" }} />
              <div style={{ position:"absolute",bottom:0,left:0,right:0,padding:"14px 12px 12px",background:"linear-gradient(0deg,rgba(5,3,1,0.92) 0%,rgba(5,3,1,0.7) 60%,transparent 100%)",textAlign:"center" }}>
                <p style={{ fontFamily:"'Cormorant Garamond',serif",fontStyle:"italic",fontSize:14,color:"#c9a84c",marginBottom:3 }}>{p.line1}</p>
                <p style={{ fontSize:10,letterSpacing:2,color:"#8a7a5a",textTransform:"uppercase" }}>{p.line2}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

/* ─── Main App ─── */
export default function App() {
  const sounds = useSoundEffects();
  const [confetti, setConfetti] = useState(false);
  const [confettiDone, setConfettiDone] = useState(false);
  const blownCount = useRef(0);
  const handleCandleBlow = () => {
    blownCount.current += 1;
    if (blownCount.current >= 5) { setConfetti(true); sounds.playChime(); }
  };
  useEffect(() => { const t = setTimeout(() => setConfetti(true), 1400); return () => clearTimeout(t); }, []);
  return (
    <div style={{ background:"#0a0705",color:"#f5edd8",fontFamily:"'Jost',sans-serif",fontWeight:300,minHeight:"100vh",overflowX:"hidden" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400&family=Jost:wght@200;300;400&display=swap');
        * { margin:0; padding:0; box-sizing:border-box; }
        @keyframes rotateBorder { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
        @keyframes flicker { 0%{transform:scaleX(1) scaleY(1) rotate(-2deg);opacity:0.9} 100%{transform:scaleX(0.85) scaleY(1.1) rotate(2deg);opacity:1} }
        @keyframes slideStrip { from{transform:translateX(0)} to{transform:translateX(-50%)} }
        @keyframes fadeUp { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:translateY(0)} }
        @keyframes lineGrow { from{width:0;opacity:0} to{width:80px;opacity:1} }
        @keyframes pulse { 0%,100%{box-shadow:0 0 20px rgba(201,168,76,0.4)} 50%{box-shadow:0 0 35px rgba(201,168,76,0.7)} }
        .wish-card:hover { transform:translateY(-4px) !important; border-color:#3a2e1a !important; }
        .wish-card:hover .wish-top-line { opacity:1 !important; }
        button:focus { outline:none; }
        @keyframes smokeRise { 0%{opacity:0.75;transform:translateX(-50%) translateY(0) scale(1)} 100%{opacity:0;transform:translateX(calc(-50% + var(--dx,4px))) translateY(-32px) scale(3)} }
        @keyframes badgePulse { 0%,100%{box-shadow:0 0 10px rgba(201,168,76,0.2)} 50%{box-shadow:0 0 22px rgba(201,168,76,0.55)} }
        .flip-card { perspective:1000px; }
        .flip-card-inner { position:relative; width:100%; transition:transform 0.6s cubic-bezier(0.4,0,0.2,1); transform-style:preserve-3d; }
        .flip-card:hover .flip-card-inner, .flip-card.flipped .flip-card-inner { transform:rotateY(180deg); }
        .flip-card-front, .flip-card-back { position:absolute; top:0; left:0; width:100%; height:100%; backface-visibility:hidden; -webkit-backface-visibility:hidden; }
        .flip-card-back { transform:rotateY(180deg); }
      `}</style>

      <Particles />
      <Confetti active={confetti && !confettiDone} onDone={() => setConfettiDone(true)} />

      <div style={{ position:"relative",zIndex:1,maxWidth:860,margin:"0 auto",padding:"0 24px 80px" }}>

        {/* Corner ornaments */}
        {[false,true].map((flip,idx) => (
          <div key={idx} style={{ position:"absolute",width:40,height:40,top:20,[flip?"right":"left"]:20,opacity:0.4,transform:flip?"scaleX(-1)":"none" }}>
            <svg viewBox="0 0 40 40" fill="none"><path d="M2 38 L2 2 L38 2" stroke="#c9a84c" strokeWidth="1" fill="none"/><circle cx="2" cy="2" r="2" fill="#c9a84c"/><path d="M2 20 L12 20 M20 2 L20 12" stroke="#c9a84c" strokeWidth="0.5" opacity="0.5"/></svg>
          </div>
        ))}

        {/* HERO */}
        <div style={{ textAlign:"center",padding:"60px 0 20px" }}>
          <div style={{ width:80,height:1,background:"linear-gradient(90deg,transparent,#c9a84c,transparent)",margin:"0 auto 24px",animation:"lineGrow 1.2s ease forwards" }} />
          <Ribbon />
          <p style={{ fontWeight:200,letterSpacing:5,fontSize:11,color:"#c9a84c",textTransform:"uppercase",animation:"fadeUp 1s ease 0.3s both" }}>A Celebration of Life &amp; Light</p>
          <h1 style={{ fontFamily:"'Cormorant Garamond',serif",fontWeight:300,fontSize:"clamp(52px,10vw,88px)",lineHeight:1,color:"#f5edd8",margin:"14px 0 8px",animation:"fadeUp 1s ease 0.6s both",letterSpacing:-1 }}>
            Ariya <span style={{ fontStyle:"italic",color:"#c9a84c" }}>Hayat</span>
          </h1>
          <p style={{ fontFamily:"'Cormorant Garamond',serif",fontWeight:300,fontSize:"clamp(14px,2.5vw,20px)",color:"#a08958",letterSpacing:4,textTransform:"uppercase",marginBottom:36,animation:"fadeUp 1s ease 0.9s both" }}>Happy Birthday</p>
          <div style={{ animation:"fadeUp 1s ease 1.1s both" }}><PhotoFrame sounds={sounds} /></div>
          <div style={{ display:"flex",justifyContent:"center",gap:14,margin:"20px 0 0",animation:"fadeUp 1s ease 1.2s both" }}>
            {[0,0.15,0.3,0.45,0.6].map((d,i) => <Candle key={i} delay={d} onBlow={handleCandleBlow} sounds={sounds} />)}
          </div>
        </div>

        {/* 🎵 MUSIC PLAYER */}
        <MusicPlayer />

        {/* QUOTES */}
        <div style={{ animation:"fadeUp 1s ease 1.4s both" }}>
          <QuoteCarousel sounds={sounds} />
        </div>

        {/* WISHES */}
        <div style={{ marginBottom:56,animation:"fadeUp 1s ease 1.7s both" }}>
          <div style={{ textAlign:"center",marginBottom:32 }}>
            <h2 style={{ fontFamily:"'Cormorant Garamond',serif",fontWeight:300,fontSize:34,color:"#f5edd8" }}>Our Wishes for You</h2>
            <div style={{ display:"flex",alignItems:"center",gap:12,justifyContent:"center",marginTop:10 }}>
              <div style={{ width:50,height:1,background:"linear-gradient(90deg,transparent,#c9a84c)" }} /><span style={{ fontSize:10,color:"#c9a84c" }}>✦</span><div style={{ width:50,height:1,background:"linear-gradient(90deg,#c9a84c,transparent)" }} />
            </div>
          </div>
          <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(200px,1fr))",gap:14 }}>
            {wishes.map((w,i) => <FlipCard key={i} wish={w} sounds={sounds} />)}
          </div>
        </div>

        {/* IMAGE STRIP */}
        <Section><ImageStrip /></Section>

        {/* BIG WISH */}
        <Section><div style={{ textAlign:"center",padding:"60px 24px",position:"relative" }}>
          <div style={{ position:"absolute",top:0,left:"50%",transform:"translateX(-50%)",width:1,height:40,background:"linear-gradient(180deg,transparent,#c9a84c)" }} />
          <p style={{ fontFamily:"'Cormorant Garamond',serif",fontSize:"clamp(24px,4.5vw,42px)",fontWeight:300,color:"#f5edd8",lineHeight:1.55,maxWidth:640,margin:"0 auto 16px" }}>
            On this <em style={{ color:"#c9a84c" }}>golden day</em>, may the universe pour back into your life every ounce of beauty, love, and joy you have given to everyone around you.
          </p>
          <p style={{ fontFamily:"'Cormorant Garamond',serif",fontSize:"clamp(20px,3.5vw,32px)",fontWeight:300,color:"#c9a84c",marginTop:20 }}>Happy Birthday, Ariya. ✦</p>
          <p style={{ fontFamily:"'Cormorant Garamond',serif",fontStyle:"italic",fontSize:15,color:"#5a4a2a",marginTop:28,letterSpacing:1 }}>— With infinite warmth and love</p>
          <div style={{ position:"absolute",bottom:0,left:"50%",transform:"translateX(-50%)",width:1,height:40,background:"linear-gradient(0deg,transparent,#c9a84c)" }} />
        </div></Section>

        {/* FOOTER */}
        <div style={{ textAlign:"center",paddingTop:40,borderTop:"1px solid #1a1408",animation:"fadeUp 1s ease 2.5s both" }}>
          <p style={{ fontSize:10,letterSpacing:3,color:"#3a2e1a",textTransform:"uppercase" }}>Made with love · For Ariya Hayat · A soul worth celebrating</p>
        </div>

      </div>
    </div>
  );
}
